<script setup lang="ts">
import { ref, watch } from 'vue'
import { RouterLink, useRouter } from 'vue-router'
import { useI18n } from '../../composables/useI18n'
import { useModals } from '../../composables/useModals'
import { useAuthStore } from '../../stores/auth'
import { PhX } from '@phosphor-icons/vue'
import type { Lang } from '../../data/translations'

const mobileMenuOpen = ref(false)
const router = useRouter()
const auth = useAuthStore()
const { t, locale, setLocale } = useI18n()
const { currentModalKey, isPricingOpen } = useModals()

function updateBodyScroll() {
  const lock = !!currentModalKey.value || isPricingOpen.value || mobileMenuOpen.value
  document.body.style.overflow = lock ? 'hidden' : ''
}
watch([currentModalKey, isPricingOpen, mobileMenuOpen], updateBodyScroll, { immediate: true })
const { openPricingModal } = useModals()

const langs: { code: Lang; label: string }[] = [
  { code: 'ca', label: 'CA' },
  { code: 'es', label: 'ES' },
  { code: 'en', label: 'EN' },
]

function isActiveLang(code: Lang) {
  return locale.value === code
}

function toggleMenu() {
  mobileMenuOpen.value = !mobileMenuOpen.value
}
function closeMenu() {
  mobileMenuOpen.value = false
}
function closeAndPricing() {
  closeMenu()
  openPricingModal()
}

async function logout() {
  await auth.logout()
  await router.push('/')
  closeMenu()
}
</script>

<template>
  <nav
    id="navbar"
    class="fixed top-0 left-0 right-0 z-100 flex items-center justify-between px-[5%] py-[18px] bg-deep/97 backdrop-blur-md border-b border-blue/15 transition-[padding] duration-300"
  >
    <RouterLink to="/" class="font-heading text-2xl font-extrabold text-white tracking-[-0.5px] no-underline">
      <img src="data:image/png;base64," alt="Lumify" style="height:36px;filter:brightness(0) invert(1);" />
    </RouterLink>

    <ul class="hidden lg:flex items-center gap-9 list-none">
      <li><a href="/#servicios" class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]">{{ t('nav.services') }}</a></li>
      <li><a href="/#packs" class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]">{{ t('nav.packs') }}</a></li>
      <li><a href="/#retainers" class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]">{{ t('nav.retainers') }}</a></li>
      <li><a href="/#metodologia" class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]">{{ t('nav.method') }}</a></li>
      <li><a href="/#nosaltres" class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]">{{ t('nav.about') }}</a></li>
      <li>
        <RouterLink
          to="/training"
          class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px] [&.router-link-exact-active]:text-blue"
        >
          {{ t('nav.training') }}
        </RouterLink>
      </li>
    </ul>

    <div class="flex items-center gap-4">
      <div class="flex gap-1 bg-white/10 rounded-full p-1">
        <button
          v-for="l in langs"
          :key="l.code"
          type="button"
          class="min-h-[44px] min-w-[44px] flex items-center justify-center border-none text-xs font-semibold py-1 px-2.5 rounded-full transition-all duration-200 font-sans uppercase tracking-wider"
          :class="isActiveLang(l.code) ? 'bg-blue text-white' : 'bg-transparent text-white/60'"
          @click="setLocale(l.code)"
        >
          {{ l.label }}
        </button>
      </div>
      <div class="hidden lg:flex items-center gap-3">
        <template v-if="auth.isAuthenticated">
          <RouterLink
            v-if="auth.hasRole('admin')"
            to="/admin"
            class="text-white/78 no-underline text-sm font-medium transition-colors hover:text-blue tracking-[0.3px]"
          >
            {{ t('nav.admin') }}
          </RouterLink>
          <button
            type="button"
            class="text-white/78 text-sm font-medium hover:text-blue bg-transparent border-none cursor-pointer tracking-[0.3px]"
            @click="logout"
          >
            {{ t('nav.logout') }}
          </button>
        </template>
      </div>
      <button
        type="button"
        class="hidden lg:inline-flex min-h-[44px] items-center bg-blue text-white py-2.5 px-5 rounded-full text-sm font-semibold transition-all duration-200 hover:bg-[#5aaeff] hover:-translate-y-px border-none cursor-pointer font-sans"
        @click="openPricingModal()"
      >
        {{ t('nav.cta') }}
      </button>
      <button
        type="button"
        class="lg:hidden flex flex-col gap-1 cursor-pointer bg-transparent border-none min-h-[44px] min-w-[44px] items-center justify-center"
        aria-label="Menu"
        @click="toggleMenu"
      >
        <span class="block w-[22px] h-0.5 bg-white rounded-sm transition-all duration-300" />
        <span class="block w-[22px] h-0.5 bg-white rounded-sm transition-all duration-300" />
        <span class="block w-[22px] h-0.5 bg-white rounded-sm transition-all duration-300" />
      </button>
    </div>
  </nav>

  <!-- Menú móvil (overlay) -->
  <div
    v-show="mobileMenuOpen"
    class="fixed inset-0 bg-deep z-99 flex flex-col items-center justify-center gap-7"
  >
    <button
      type="button"
      class="absolute top-6 right-[5%] min-h-[44px] min-w-[44px] flex items-center justify-center bg-transparent border-none text-white text-3xl cursor-pointer"
      aria-label="Cerrar"
      @click="closeMenu"
    >
      <PhX :size="28" weight="bold" />
    </button>
    <a href="/#servicios" class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue" @click="closeMenu">{{ t('nav.services') }}</a>
    <a href="/#packs" class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue" @click="closeMenu">{{ t('nav.packs') }}</a>
    <a href="/#retainers" class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue" @click="closeMenu">{{ t('nav.retainers') }}</a>
    <a href="/#metodologia" class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue" @click="closeMenu">{{ t('nav.method') }}</a>
    <a href="/#nosaltres" class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue" @click="closeMenu">{{ t('nav.about') }}</a>
    <RouterLink
      to="/training"
      class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue"
      @click="closeMenu"
    >
      {{ t('nav.training') }}
    </RouterLink>
    <template v-if="auth.isAuthenticated">
      <RouterLink
        v-if="auth.hasRole('admin')"
        to="/admin"
        class="min-h-[44px] flex items-center text-white no-underline text-2xl font-heading font-bold hover:text-blue"
        @click="closeMenu"
      >
        {{ t('nav.admin') }}
      </RouterLink>
      <button
        type="button"
        class="min-h-[44px] flex items-center text-white text-2xl font-heading font-bold hover:text-blue bg-transparent border-none cursor-pointer"
        @click="logout"
      >
        {{ t('nav.logout') }}
      </button>
    </template>
    <button
      type="button"
      class="min-h-[44px] inline-flex items-center bg-blue text-white py-2.5 px-5 rounded-full text-sm font-semibold no-underline border-none cursor-pointer font-sans"
      @click="closeAndPricing"
    >
      {{ t('nav.cta') }}
    </button>
  </div>
</template>
